mapper.select:
select * from fish_points_goods

    AND name like concat('%', #{name}, '%')
    AND type = #{type}
    AND status = #{status}

order by sort_num asc, goods_id asc

mapper.update:
update fish_points_goods
name = #{name}, image = #{image}, type = #{type}, points_cost = #{pointsCost}, stock = #{stock}, related_id = #{relatedId}, duration_minutes = #{durationMinutes}, sort_num = #{sortNum}, status = #{status}, update_time = sysdate()
where goods_id = #{goodsId}

mapper.select:
select e.*, u.nickname from fish_points_exchange e left join fish_user u on u.user_id = e.user_id

    AND e.user_id = #{userId}
    AND e.status = #{status}

order by e.create_time desc

mapper.update:
update fish_user set points = points + #{delta}
where user_id = #{userId}
and points + #{delta} >= 0

mapper.select:
select date_format(checkin_date, '%Y-%m-%d') from fish_checkin
where user_id = #{userId} and date_format(checkin_date, '%Y-%m') = #{month}
order by checkin_date asc
